import json
from elasticsearch import Elasticsearch, RequestsHttpConnection

es = Elasticsearch(
    hosts=["localhost"],
    connection_class=RequestsHttpConnection
)

def execute_script(script):
    # Validate untrusted input and use secure platform APIs
    script = json.loads(script)
    if not isinstance(script, dict):
        raise ValueError("Invalid script format")
    if "inline" not in script or not script["inline"]:
        raise ValueError("Script must be an inline script")
    if "source" not in script or not script["source"]:
        raise ValueError("Script must have a source code")

    # Apply least privilege and explicit allowlists where relevant
    es.cluster.put_settings(body={"transient": {"script.inline": True}})

    # Keep secrets, tokens, and sensitive data out of plaintext storage and logs
    es.indices.create(index="my-index", body={"mappings": {"properties": {"my-field": {"type": "keyword"}}}})

    # Execute the script using Elasticsearch Script API
    result = es.search(index="my-index", body={"script": script})
    return result